// Parser la réponse de l'AI Agent
const raw = $input.item.json.output;
let analyse;

try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  analyse = JSON.parse(cleaned);
} catch(e) {
  analyse = {
    est_signalement: true,
    sentiment: 'negatif',
    score_sentiment: 5,
    ligne_detectee: '',
    arret_detecte: '',
    type_incident: 'Non déterminé',
    gravite: 'moyen',
    resume: raw.substring(0, 200),
    reponse_privee: 'Bonjour, nous avons bien reçu votre message. Pouvez-vous nous contacter via notre formulaire officiel sur ratp.fr/signalement ou appeler le 3424 ?',
    should_create_report: true
  };
}

const body = $('Webhook - Post Réseau Social').item.json.body;

return [{
  json: {
    // Données du post original
    network: body.network || 'Twitter/X',
    author: body.author || '@anonyme',
    message: body.message || '',
    hashtags: body.hashtags || [],
    post_date: body.date || new Date().toISOString(),
    // Analyse IA
    est_signalement: analyse.est_signalement || false,
    sentiment: analyse.sentiment || 'neutre',
    score_sentiment: analyse.score_sentiment || 0,
    ligne_detectee: analyse.ligne_detectee || '',
    arret_detecte: analyse.arret_detecte || '',
    type_incident: analyse.type_incident || '',
    gravite: analyse.gravite || 'faible',
    resume: analyse.resume || '',
    reponse_privee: analyse.reponse_privee || '',
    should_create_report: analyse.should_create_report || false
  }
}];
